import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer
} from 'recharts';
import './Dashboard.css';

// API configuration
const API_CONFIG = {
  baseURL: 'https://api.orbititer.finance',
  timeout: 10000,
  retryAttempts: 3,
  retryDelay: 1000
};

// Custom hook for API calls with retry logic
const useApiCall = (endpoint, interval = 30000) => {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchData = useCallback(async (retryCount = 0) => {
    try {
      setLoading(true);
      setError(null);

      const response = await axios.get(`${API_CONFIG.baseURL}${endpoint}`, {
        timeout: API_CONFIG.timeout,
        headers: {
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        }
      });

      setData(response.data);
    } catch (err) {
      console.error(`API call failed for ${endpoint}:`, err);

      if (retryCount < API_CONFIG.retryAttempts) {
        setTimeout(() => {
          fetchData(retryCount + 1);
        }, API_CONFIG.retryDelay * (retryCount + 1));
      } else {
        setError(err.message || 'Failed to fetch data');
      }
    } finally {
      setLoading(false);
    }
  }, [endpoint]);

  useEffect(() => {
    fetchData();

    const intervalId = setInterval(fetchData, interval);

    return () => clearInterval(intervalId);
  }, [fetchData, interval]);

  return { data, loading, error, refetch: fetchData };
};

