    .trim()
    .escape(),
  query('category')
    .optional()
    .isIn(['all', 'batteries', 'audio', 'engine', 'electrical', 'suspension', 'brakes'])
    .withMessage('Invalid category'),
  query('page')
    .optional()
    .isInt({ min: 1, max: 1000 })
    .withMessage('Page must be a positive integer between 1 and 1000'),
  query('limit')
