        if (!apiKey) {
            throw new Error('API key is required for SolanaGate authentication');
        }

        this.apiKey = apiKey;
        this.connection = new Connection(CONFIG.SOLANA_RPC_URL, 'confirmed');
        this.axiosInstance = axios.create({
